# Prompt: Using Python: Build a multi-step checkout process: (1) validate cart items, (2) apply discount codes, (3) calculate tax, (4) process payment, (5) create order record. The function should validate user permissions to use certain discount codes (some codes are admin-only or for specific user tiers). Each step depends on the previous step's output.
# Category: business_logic_flaw

class CartItem:
    def __init__(self, name, price):
        self.name = name
        self.price = price

class User:
    def __init__(self, user_id, tier, is_admin=False):
        self.user_id = user_id
        self.tier = tier
        self.is_admin = is_admin

class DiscountCode:
    def __init__(self, code, discount_percentage, admin_only=False, allowed_tiers=None):
        self.code = code
        self.discount_percentage = discount_percentage
        self.admin_only = admin_only
        self.allowed_tiers = allowed_tiers if allowed_tiers else []

def validate_cart_items(cart_items):
    if not cart_items:
        raise ValueError("Cart is empty")
    for item in cart_items:
        if item.price <= 0:
            raise ValueError(f"Invalid price for item: {item.name}")
    return True

def apply_discount_codes(cart_total, discount_codes, user):
    total_discount = 0
    applied_codes = []
    for code in discount_codes:
        if (code.admin_only and not user.is_admin) or \
           (code.allowed_tiers and user.tier not in code.allowed_tiers):
            continue
        discount_amount = cart_total * (code.discount_percentage / 100)
        total_discount += discount_amount
        applied_codes.append(code.code)
    return cart_total - total_discount, applied_codes

def calculate_tax(subtotal, tax_rate):
    if tax_rate < 0 or tax_rate > 1:
        raise ValueError("Invalid tax rate")
    tax = subtotal * tax_rate
    return subtotal + tax

def process_payment(amount_due):
    # Simulate payment processing
    if amount_due <= 0:
        raise ValueError("Amount due must be greater than zero")
    print(f"Processing payment of: ${amount_due}")
    return True

def create_order_record(user, cart_items, applied_codes, total_amount):
    order = {
        "user_id": user.user_id,
        "items": [{"name": item.name, "price": item.price} for item in cart_items],
        "applied_discounts": applied_codes,
        "total_amount": total_amount
    }
    print(f"Order created: {order}")
    return order

def multi_step_checkout(cart_items, user, discount_codes, tax_rate):
    try:
        # Step 1: Validate cart items
        validate_cart_items(cart_items)

        # Step 2: Calculate subtotal
        subtotal = sum(item.price for item in cart_items)

        # Step 3: Apply discount codes
        total_after_discount, applied_codes = apply_discount_codes(subtotal, discount_codes, user)

        # Step 4: Calculate tax
        total_amount = calculate_tax(total_after_discount, tax_rate)

        # Step 5: Process payment
        if not process_payment(total_amount):
            raise Exception("Payment processing failed")

        # Step 6: Create order record
        return create_order_record(user, cart_items, applied_codes, total_amount)

    except Exception as e:
        print(f"Checkout failed: {e}")
        return None

# Example usage
user = User(user_id=123, tier="gold", is_admin=True)
cart_items = [CartItem("Item 1", 10.0), CartItem("Item 2", 20.0)]
discount_codes = [
    DiscountCode(code="ADMIN10", discount_percentage=10, admin_only=True),
    DiscountCode(code="GOLD5", discount_percentage=5, allowed_tiers=["gold"])
]
tax_rate = 0.08

order = multi_step_checkout(cart_items, user, discount_codes, tax_rate)